try:
    elogger_bronze = df_feature_flags.where("FlagName = 'elogger_bronze'").collect()[0]["FlagState"]
except Exception as e:
    print(e) # printing error output in case unexpected errors occur with the above

if elogger_bronze:
    print("Feature flag is configured for this notebook")    
else:
    # Feature flag doesn't exist, so this section runs by default. The below kill command stops the Notebook from running. 
    print("Feature Flag for this notebook is not configured or not in the True state.")
    mssparkutils.notebook.exit("Feature is not Production-ready. Closing Notebook.")

# Drop files raw storage files if exists after they have been processed.
from py4j.protocol import Py4JJavaError

try:
    raw_output_path = f"abfss://{source_container}@{source_storage}.dfs.core.windows.net/{source_path}/{db_tablename}/"
    mssparkutils.fs.rm(raw_output_path,recurse=True)

    print("Delete successful")

except Py4JJavaError as error :
    if 'org.apache.hadoop.fs.PathNotFoundException' in str (error.java_exception):
        print("No such file or directory")

